+    fn buildColumnDescriptors(
+        self: FileMetaData,
+        allocator: std.mem.Allocator,
+        descriptors: *std.ArrayListUnmanaged(ColumnDescriptor),
+        path: *std.ArrayListUnmanaged([]const u8),
+        idx: *usize,
