+                .type_ = elem.type_ orelse .byte_array,
+                .type_length = elem.type_length,
+                .repetition_type = elem.repetition_type orelse .required,
+                .converted_type = elem.converted_type,
+                .scale = elem.scale,
+                .precision = elem.precision,
+            });
